<script setup lang="ts">const p=withDefaults(defineProps<{modelValue?:string;label?:string;placeholder?:string;state?:'default'|'error'|'disabled';tone?:'life'|'study';icon?:string;message?:string}>(),{state:'default',tone:'life'});const emit=defineEmits<{"update:modelValue":[string]}>()</script><template><label class="xj-field"><span v-if="label" class="xj-label">{{label}}</span><span class="xj-input-wrap" :class="[tone,state]"><img v-if="icon" :src="icon" class="xj-icon sm" alt=""/><input class="xj-input" :value="modelValue" :placeholder="placeholder" :disabled="state==='disabled'" @input="emit('update:modelValue',($event.target as HTMLInputElement).value)"/></span><span v-if="message" :class="state==='error'?'xj-error':'xj-help'">{{message}}</span></label></template>
